import csv
import uuid
import os
from datetime import datetime
import torch
import functools

import pennylane as qp

from functions import train, show_results, build_model, get_device

# ------------------------------------------------------------------
# Paths (override before importing if needed)
# ------------------------------------------------------------------
EXPERIMENTS_CSV = "experiments.csv"
COSTS_CSV       = "costs.csv"

EXPERIMENTS_FIELDS = [
    "id",
    "timestamp",
    "circuit_num",
    "n_qubits",
    "layers",
    "anzats_reps",
    "n_params",
    "n_train_samples",
    "max_steps",
    "batch_size",
    "final_cost",
    "initial_cost",
    "notes",
]

COSTS_FIELDS = ["experiment_id", "n_steps"]


def _ensure_csv(path: str, fieldnames: list[str]) -> None:
    """Create the CSV with a header row if it does not exist yet."""
    directory = os.path.dirname(path)
    if directory:
        os.makedirs(directory, exist_ok=True)
    if not os.path.exists(path):
        with open(path, "w", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()


def _append_row(path: str, fieldnames: list[str], row: dict) -> None:
    with open(path, "a", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writerow(row)


def _append_rows(path: str, fieldnames: list[str], rows: list[dict]) -> None:
    with open(path, "a", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writerows(rows)


def load_experiments(experiments_csv: str = EXPERIMENTS_CSV, path: str = None):
    """Return all experiment summary rows as a list of dicts."""
    if path is not None:
        experiments_csv = os.path.join(path, experiments_csv)
    _ensure_csv(experiments_csv, EXPERIMENTS_FIELDS)
    with open(experiments_csv, "r", newline="") as f:
        return list(csv.DictReader(f))


def load_costs(costs_csv: str = COSTS_CSV, path: str = None):
    """
    Return cost rows. If `experiment_id` is given, filter to that run only.
    Returns a list of dicts with keys: experiment_id, step, cost.
    """
    if path is not None:
        costs_csv = os.path.join(path, costs_csv)
    # Ensure file exists (will create with minimal header if missing)
    _ensure_csv(costs_csv, COSTS_FIELDS)
    with open(costs_csv, "r", newline="") as f:
        reader = csv.DictReader(f)
        header = reader.fieldnames or []
        rows = list(reader)

    # Backward-compatible parsing:
    # - If file has 'step' and 'cost' columns, return list of {experiment_id, step, cost}
    # - If file uses wide format cost_0, cost_1, ... return list of {experiment_id, n_steps, costs: [...]}
    if "step" in header and "cost" in header:
        return rows

    # detect cost_* columns
    cost_cols = [c for c in header if c.startswith("cost_")]
    if cost_cols:
        parsed = []
        # sort cost columns by index
        def idx(name):
            try:
                return int(name.split("_")[1])
            except Exception:
                return 0

        cost_cols = sorted(cost_cols, key=idx)
        for r in rows:
            costs = []
            for c in cost_cols:
                v = r.get(c, "")
                costs.append(float(v) if v != "" else None)
            parsed.append({
                "experiment_id": r.get("experiment_id"),
                "n_steps": int(r.get("n_steps", len(costs))) if r.get("n_steps") else len(costs),
                "costs": costs,
            })
        return parsed

    # default fallback
    return rows



# ------------------------------------------------------------------
# Public API
# ------------------------------------------------------------------

def train_and_record(
    x,
    target_y,
    circuit_num: int,
    n_qubits: int,
    layers: int,
    anzats_reps: int,
    max_steps: int = 200,
    batch_size: int = 100,
    display_step: int = 10,
    notes: str = "",
    experiments_csv: str = EXPERIMENTS_CSV,
    costs_csv: str = COSTS_CSV,
    train_fn = train,
    path: str = "results/",
):
    """
    Run `train`, then persist metadata + cost curve to CSV files.

    Parameters
    ----------
    model, weights, x, target_y :
        Passed straight through to `train`.
    circuit_num : int
        The circuit index (1-19) used in this experiment.
    n_qubits : int
        Number of qubits.
    reps : int
        Number of repetitions of the ansatz.
    max_steps, batch_size, display_step :
        Training hyper-parameters forwarded to `train`.
    notes : str
        Any free-text annotation to attach to this run.
    experiments_csv : str
        Path to the experiments summary CSV.
    costs_csv : str
        Path to the per-step cost CSV.

    Returns
    -------
    experiment_id : str
        UUID of the recorded experiment.
    final_weights : torch.Tensor
    cost_history : torch.Tensor  shape (max_steps,)
    """
    experiments_csv = experiments_csv if path is None else os.path.join(path, experiments_csv)
    costs_csv       = costs_csv       if path is None else os.path.join(path, costs_csv)

    _ensure_csv(experiments_csv, EXPERIMENTS_FIELDS)
    # ensure costs CSV exists with a header matching this run's max_steps
    cost_fieldnames = ["experiment_id", "n_steps"] + [f"cost_{i}" for i in range(max_steps)]
    _ensure_csv(costs_csv, cost_fieldnames)

    experiment_id = str(uuid.uuid4())
    timestamp     = datetime.now().isoformat(timespec="seconds")

    # ---- run training ------------------------------------------------
    model,weights = build_model(circuit_num, n_qubits, layers, anzats_reps, measuring_qubit=n_qubits-1)

    final_weights, cst = train_fn(
        model, weights, x, target_y,
        max_steps=max_steps,
        batch_size=batch_size,
        display_step=display_step,
        display=False,
    )

    # ---- write experiment summary row --------------------------------
    exp_row = {
        "id":               experiment_id,
        "timestamp":        timestamp,
        "circuit_num":      circuit_num,
        "n_qubits":         n_qubits,
        "layers":            layers,
        "anzats_reps":             anzats_reps,
        "n_params":         int(weights.numel()),
        "n_train_samples":  len(x),
        "max_steps":        max_steps,
        "batch_size":       batch_size,
        "initial_cost":     round(float(cst[0].item()), 8),
        "final_cost":       round(float(cst[-1].item()), 8),
        "notes":            notes,
    }
    _append_row(experiments_csv, EXPERIMENTS_FIELDS, exp_row)

    # ---- write per-experiment costs on a single row -------------------
    cost_row = {"experiment_id": experiment_id, "n_steps": max_steps}
    for step in range(max_steps):
        cost_row[f"cost_{step}"] = round(float(cst[step].item()), 8)
    _append_row(costs_csv, cost_fieldnames, cost_row)

    print(f"[tracker] Experiment {experiment_id} saved "
          f"(circuit={circuit_num}, qubits={n_qubits}, layers={layers}, "
          f"final_cost={exp_row['final_cost']:.6f})")

    return experiment_id, final_weights, cst


